import{_ as t,o,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"38. Uniforms","description":"","frontmatter":{"title":"38. Uniforms","eba":"Medical Specialists 2022-2026","topics":["allowances","uniforms"]},"headers":[],"relativePath":"ebas/medical-specialists/allowances/38-uniforms.md","filePath":"ebas/medical-specialists/allowances/38-uniforms.md"}'),a={name:"ebas/medical-specialists/allowances/38-uniforms.md"};function i(n,e,c,l,m,h){return o(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_38-uniforms" tabindex="-1">38. Uniforms <a class="header-anchor" href="#_38-uniforms" aria-label="Permalink to &quot;38. Uniforms&quot;">​</a></h1><p><strong>38.1</strong> Each Doctor will be reimbursed for the cost of uniform clothing where:</p><p><strong>(a)</strong> the Doctor&#39;s duties necessitate the wearing of uniform clothing; or</p><p><strong>(b)</strong> it is the usual custom in the industry for a Doctor to wear uniform clothing.</p><p><strong>38.2</strong> Reimbursement under this clause need not be made if the Health Service provides the relevant uniform clothing, which remains the property of the Health Service and must be returned at the completion of the Doctor&#39;s period of service at that Health Service. For the purposes of this clause, the Health Service may deem white coats to constitute a uniform.</p>',5)])])}const p=t(a,[["render",i]]);export{u as __pageData,p as default};
